    33→    @Default(null) String? name,
    34→    @Default(null) String? ownerUserId,
    35→    @Default(TeamType.multiple) TeamType teamType,
    36→    @Default(null) DateTime? createdAt, // assumes UTC
    37→    @Default(null) DateTime? updatedAt, // assumes UTC
    38→    @Default(null) DateTime? teamPlanCancelAt,
    39→    @Default(null) DateTime? teamPlanDowngradeAt,
    40→    @Default(null) String? imageUrl,
    41→    @Default(null) TeamPlan? teamPlan,
    42→    @Default(null) TeamPlan? nextTeamPlan,
    43→    @Default(null) String? presignedImageUrl,
    44→    @Default(null) String? billingFailureReason,
    45→    @Default(null) String? downgradePlanId,
    46→    @Default(null) Item? item,
    47→    @Default(null) List<UserInfo>? users,
    48→  }) = _Team;
    49→
    50→  factory Team.fromJson(Map<String, dynamic> json) => _$TeamFromJson(json);
    51→
    52→  bool get isSingleUserTeam => teamType == TeamType.single;
    53→
    54→  /// ボール解析の使用量（TeamPlan + Item の合算）
    55→  int get ballUsage {
    56→    // プランの上限
    57→    final planMax =
    58→        (teamPlan?.withinPeriod ?? false) ? teamPlan?.plan?.maxBalls ?? 0 : 0;
    59→
    60→    // プランの使用量
    61→    final rawPlanUsage =
    62→        (teamPlan?.withinPeriod ?? false) ? teamPlan?.currentUsage ?? 0 : 0;
    63→
    64→    // 上限を越えないようにする
    65→    // DB 上で maxBalls == 300 にも関わらず、currentUsage == 10000 などが入った場合
    66→    // currentUsage = 300 にクランプ
    67→    final planUsage = min(rawPlanUsage, planMax);
    68→
    69→    final itemMax = item?.ballAvailableCount ?? 0;
    70→    final itemUsage = min(item?.ballUsage ?? 0, itemMax);
    71→
    72→    return planUsage + itemUsage;
    73→  }
    74→
    75→  /// AI コーチの使用量（TeamPlan + Item の合算）
    76→  int get aiCoachUsage {
    77→    final planMax = (teamPlan?.withinPeriod ?? false)
    78→        ? teamPlan?.plan?.maxAiCoachs ?? 0
    79→        : 0;
    80→
    81→    final rawPlanUsage = (teamPlan?.withinPeriod ?? false)
    82→        ? teamPlan?.currentAiCoachUsage ?? 0
    83→        : 0;
    84→
    85→    final planUsage = min(rawPlanUsage, planMax);
    86→
    87→    final itemMax = item?.aiCoachAvailableCount ?? 0;
    88→    final itemUsage = min(item?.aiCoachUsage ?? 0, itemMax);
    89→
    90→    return planUsage + itemUsage;
    91→  }
    92→
    93→  /// ボール解析の上限数（Plan + Item の合算）
    94→  int get maxBalls {
    95→    final planMax =
    96→        (teamPlan?.withinPeriod ?? false) ? teamPlan?.plan?.maxBalls ?? 0 : 0;
    97→    final itemMax = item?.ballAvailableCount ?? 0;
    98→    return planMax + itemMax;
    99→  }
   100→
   101→  /// AI コーチの上限数（Plan + Item の合算）
   102→  int get maxAICoachCount {
   103→    final planMax = (teamPlan?.withinPeriod ?? false)
   104→        ? teamPlan?.plan?.maxAiCoachs ?? 0
   105→        : 0;
   106→    final itemMax = item?.aiCoachAvailableCount ?? 0;
   107→    return planMax + itemMax;
   108→  }
   109→
   110→  /// プランの契約・有効期限状態
   111→  TeamPlanStatus get teamPlanStatus {
   112→    // 1. teamPlanがnull
   113→    if (teamPlan == null) {
   114→      if (nextTeamPlan != null) {
   115→        return TeamPlanStatus.nextPlanPending;
   116→      }
   117→      return TeamPlanStatus.noContract;
   118→    }
   119→
   120→    // 2. 期限切れか
   121→    final now = resolveTeamPlanNow();
   122→    final endDate = teamPlan!.endDate;
   123→    // 以下の場合は nextTeamPlan の endDate を使用する
   124→    // 1. nextTeamPlan が存在
   125→    // 2. teamPlan の endDate が nextTeamPlan の startDate と同じ (連続してプランを継続している)
   126→    final effectiveEndDate =
   127→        (nextTeamPlan != null && endDate == nextTeamPlan!.startDate)
   128→            ? nextTeamPlan!.endDate
   129→            : endDate;
   130→    final isExpired =
   131→        effectiveEndDate != null && effectiveEndDate.isBefore(now);
   132→    if (isExpired) {
   133→      if (nextTeamPlan != null) {
   134→        return TeamPlanStatus.nextPlanPending;
   135→      }
   136→      return TeamPlanStatus.expired;
   137→    }
   138→
   139→    // 3. 期限警告（30日以内）
   140→    if (effectiveEndDate != null) {
   141→      final oneMonthLater = now.add(const Duration(days: 30));
   142→      if (effectiveEndDate.isAfter(now) &&
   143→          effectiveEndDate.isBefore(oneMonthLater)) {
   144→        return TeamPlanStatus.expiringSoon;
   145→      }
   146→    }
   147→
   148→    // 4. 問題なし
   149→    return TeamPlanStatus.ok;
   150→  }
   151→
   152→  /// ボール解析の使用量状態
   153→  BallAnalysisUsageStatus get ballAnalysisUsageStatus {
   154→    final usage = ballUsage;
   155→    final maxUsage = maxBalls;
   156→
   157→    // 上限到達
   158→    if (usage >= maxUsage) {
   159→      return BallAnalysisUsageStatus.limitReached;
   160→    }
   161→
   162→    // 上限接近（90%以上）
   163→    if (usage >= (maxUsage * 0.9).floor()) {
   164→      return BallAnalysisUsageStatus.limitApproaching;
   165→    }
   166→
   167→    // 正常
   168→    return BallAnalysisUsageStatus.ok;
   169→  }
