   184→    }
   185→
   186→    // 正常
   187→    return AICoachUsageStatus.ok;
   188→  }
   189→
   190→  /// ボール解析が実行可能かどうか
   191→  bool get canAnalyzeBall {
   192→    return ballAnalysisUsageStatus.canAnalyze;
   193→  }
   194→
   195→  /// AI コーチが利用可能かどうか
   196→  bool get canUseAiCoach {
   197→    return aiCoachUsageStatus.canUseAiCoach;
   198→  }
   199→
   200→  /// チームオーナーのメールアドレス
   201→  String? get ownerEmail {
   202→    if (ownerUserId == null || users == null) return null;
   203→    try {
   204→      final owner = users!.firstWhere(
   205→        (user) => user.id == ownerUserId,
   206→        orElse: () => throw StateError('Owner not found'),
   207→      );
   208→      return owner.email;
   209→    } catch (_) {
   210→      return null;
   211→    }
   212→  }
   213→}
   214→
   215→/// チームプランの契約・有効期限に関する状態
   216→enum TeamPlanStatus {
   217→  // アプリ利用不可
   218→  noContract, // 有料プラン契約なし
   219→  nextPlanPending, // 次回プランが保留中
   220→  expired, // 期限切れ
   221→
   222→  // アプリ利用可（警告あり）
   223→  expiringSoon, // 30日以内に期限切れ
   224→
   225→  // アプリ利用可（正常）
   226→  ok,
   227→  ;
   228→
   229→  /// プランが有効かどうか（契約があり、期限内）
   230→  bool get isValid => this == expiringSoon || this == ok;
   231→}
   232→
