   234→enum BallAnalysisUsageStatus {
   235→  // 解析不可
   236→  limitReached, // 上限到達（currentUsage >= maxBalls）
   237→
   238→  // 解析可（警告あり）
   239→  limitApproaching, // 上限接近（currentUsage >= maxBalls * 0.9）
   240→
   241→  // 解析可（正常）
   242→  ok,
   243→  ;
   244→
   245→  /// 解析実行可能かどうか
   246→  bool get canAnalyze => this == limitApproaching || this == ok;
   247→
   248→  /// 警告を表示すべきかどうか
   249→  bool get shouldWarn => this == limitApproaching;
   250→}
   251→
   252→/// AI コーチの使用量状態
   253→enum AICoachUsageStatus {
   254→  // AI コーチ利用不可
   255→  limitReached, // 上限到達（currentAiCoachUsage >= maxAiCoachs）
   256→
   257→  // AI コーチ利用可（警告あり）
   258→  limitApproaching, // 上限接近（currentAiCoachUsage >= maxAiCoachs * 0.9）
   259→
   260→  // AI コーチ利用可（正常）
   261→  ok,
   262→  ;
   263→
   264→  /// AI コーチ利用可能かどうか
   265→  bool get canUseAiCoach => this == limitApproaching || this == ok;
   266→}
